   1 | import type { ISdk } from "iii-sdk";
   2 | import type {
   3 |   CompactLessonResult,
   4 |   CompactSearchResult,
   5 |   CompressedObservation,
   6 |   HybridSearchResult,
   7 |   Lesson,
   8 | } from "../types.js";
   9 | import { KV } from "../state/schema.js";
  10 | import { StateKV } from "../state/kv.js";
  11 | import { recordAccessBatch } from "./access-tracker.js";
  12 | import { getAgentId, isAgentScopeIsolated } from "../config.js";
  13 | import { logger } from "../logger.js";
  14 | 
  15 | // Compact mode trims each lesson's content for at-a-glance display. The
  16 | // full content is fetched via memory_lesson_recall when the caller needs it.
  17 | const LESSON_CONTENT_PREVIEW_CHARS = 240;
  18 | 
  19 | export function registerSmartSearchFunction(
  20 |   sdk: ISdk,
  21 |   kv: StateKV,
  22 |   searchFn: (query: string, limit: number) => Promise<HybridSearchResult[]>,
  23 | ): void {
  24 |   sdk.registerFunction("mem::smart-search",
  25 |     async (data: {
  26 |       query?: string;
  27 |       expandIds?: Array<string | { obsId: string; sessionId: string }>;
  28 |       limit?: number;
  29 |       project?: string;
  30 |       includeLessons?: boolean;
  31 |       // optional per-call agent filter for runtimes routing many
  32 |       // roles through one server. "*" opts out of the env-default
  33 |       // scope and returns hits from every agent.
  34 |       agentId?: string;
  35 |     }) => {
  36 | 
  37 |       // Compute the agent filter once, up front. Both the expandIds
  38 |       // branch and the hybrid-search branch consult it — otherwise
  39 |       // expandIds becomes a cross-agent leak (#554 follow-up).
  40 |       const isolated = isAgentScopeIsolated();
  41 |       const explicitAgentId =
  42 |         typeof data.agentId === "string" && data.agentId.trim().length > 0
  43 |           ? data.agentId.trim()
  44 |           : undefined;
  45 |       const wildcardAgent = explicitAgentId === "*";
  46 |       const filterAgentId = wildcardAgent
  47 |         ? undefined
  48 |         : explicitAgentId ?? (isolated ? getAgentId() : undefined);
  49 | 
  50 |       if (data.expandIds && data.expandIds.length > 0) {
  51 |         const raw = data.expandIds.slice(0, 20);
  52 |         const items = raw.map((entry) => {
  53 |           if (typeof entry === "string") return { obsId: entry, sessionId: undefined as string | undefined };
  54 |           if (entry && typeof entry === "object" && typeof (entry as any).obsId === "string") {
  55 |             return { obsId: (entry as any).obsId, sessionId: (entry as any).sessionId as string | undefined };
  56 |           }
  57 |           return null;
  58 |         }).filter((item): item is NonNullable<typeof item> => item !== null);
  59 | 
  60 |         const expanded: Array<{
  61 |           obsId: string;
  62 |           sessionId: string;
  63 |           observation: CompressedObservation;
  64 |         }> = [];
  65 | 
  66 |         const results = await Promise.all(
  67 |           items.map(({ obsId, sessionId }) =>
  68 |             findObservation(kv, obsId, sessionId).then((obs) =>
  69 |               obs ? { obsId, sessionId: obs.sessionId, observation: obs } : null,
  70 |             ),
  71 |           ),
  72 |         );
  73 |         for (const r of results) {
  74 |           if (r) expanded.push(r);
  75 |         }
  76 | 
  77 |         const scoped = filterAgentId
  78 |           ? expanded.filter((e) => e.observation.agentId === filterAgentId)
  79 |           : expanded;
  80 | 
  81 |         void recordAccessBatch(
  82 |           kv,
  83 |           scoped.map((e) => e.observation.id),
  84 |         );
  85 | 
  86 |         const truncated = data.expandIds.length > raw.length;
  87 |         logger.info("Smart search expanded", {
  88 |           requested: data.expandIds.l...

